export interface PreventableActivationEvent {
  preventDefault(): void;
  stopPropagation(): void;
}

export type ButtonActivationResult = "invoked" | "prevented-pending";

export function runButtonActivation<Event extends PreventableActivationEvent>(
  pending: boolean,
  event: Event,
  handler?: (event: Event) => void,
): ButtonActivationResult {
  if (pending) {
    event.preventDefault();
    event.stopPropagation();
    return "prevented-pending";
  }

  handler?.(event);
  return "invoked";
}

export type AccessibleNameSource =
  "aria-label" | "aria-labelledby" | "descendant-text" | "image-alt";

export type AccessibleNameInspection =
  | { readonly status: "present"; readonly source: AccessibleNameSource }
  | { readonly status: "missing" }
  | { readonly status: "indeterminate" };

interface ElementLike {
  readonly type?: unknown;
  readonly props?: Record<string, unknown>;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function hasNonEmptyText(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function inspectDescendant(node: unknown): AccessibleNameInspection {
  if (typeof node === "number") {
    return { status: "present", source: "descendant-text" };
  }
  if (typeof node === "string") {
    return node.trim().length > 0
      ? { status: "present", source: "descendant-text" }
      : { status: "missing" };
  }
  if (node === null || node === undefined || typeof node === "boolean") {
    return { status: "missing" };
  }
  if (Array.isArray(node)) {
    const inspections = node.map(inspectDescendant);
    return (
      inspections.find((inspection) => inspection.status === "present") ??
      (inspections.some((inspection) => inspection.status === "indeterminate")
        ? { status: "indeterminate" }
        : { status: "missing" })
    );
  }
  if (!isRecord(node)) {
    return { status: "indeterminate" };
  }

  const element = node as ElementLike;
  const props = element.props;
  if (!isRecord(props)) {
    return { status: "indeterminate" };
  }
  if (hasNonEmptyText(props["aria-label"])) {
    return { status: "present", source: "aria-label" };
  }
  if (hasNonEmptyText(props["aria-labelledby"])) {
    return { status: "present", source: "aria-labelledby" };
  }

  if (typeof element.type === "string") {
    if (element.type === "svg") {
      if (props["aria-hidden"] === true || props["aria-hidden"] === "true") {
        return { status: "missing" };
      }
      const svgName = inspectDescendant(props.children);
      return svgName.status === "present" ? svgName : { status: "indeterminate" };
    }
    if (element.type === "img") {
      return hasNonEmptyText(props.alt)
        ? { status: "present", source: "image-alt" }
        : { status: "missing" };
    }
    if (props.dangerouslySetInnerHTML !== undefined) {
      return { status: "indeterminate" };
    }
  }

  if ("children" in props) {
    return inspectDescendant(props.children);
  }

  // A custom component can render text that is not inspectable from its props.
  return typeof element.type === "string" ? { status: "missing" } : { status: "indeterminate" };
}

export function inspectButtonAccessibleName(input: {
  readonly ariaLabel?: unknown;
  readonly ariaLabelledBy?: unknown;
  readonly children?: unknown;
  readonly title?: unknown;
}): AccessibleNameInspection {
  if (hasNonEmptyText(input.ariaLabel)) {
    return { status: "present", source: "aria-label" };
  }
  if (hasNonEmptyText(input.ariaLabelledBy)) {
    return { status: "present", source: "aria-labelledby" };
  }
  // A title can contribute a fallback name, but this source-level guard cannot
  // establish how the target browser/assistive-technology pair exposes it.
  if (hasNonEmptyText(input.title)) {
    return { status: "indeterminate" };
  }
  return inspectDescendant(input.children);
}

export const MISSING_BUTTON_NAME_DIAGNOSTIC =
  "[Mergora Button] An accessible name could not be found for this icon-only button. " +
  "Add visible text, a non-empty aria-label, or aria-labelledby that references visible or " +
  "screen-reader-readable text.";

const reportedDiagnostics = new Set<string>();

interface ProcessLike {
  readonly env?: { readonly NODE_ENV?: string };
}

declare const process: ProcessLike | undefined;

function isProductionRuntime(): boolean {
  const viteProduction = (
    import.meta as ImportMeta & { readonly env?: { readonly PROD?: boolean } }
  ).env?.PROD;
  if (viteProduction === true) return true;
  return typeof process !== "undefined" && process.env?.NODE_ENV === "production";
}

export function reportButtonNameDiagnostic(inspection: AccessibleNameInspection): void {
  if (
    inspection.status !== "missing" ||
    isProductionRuntime() ||
    reportedDiagnostics.has(MISSING_BUTTON_NAME_DIAGNOSTIC)
  ) {
    return;
  }

  reportedDiagnostics.add(MISSING_BUTTON_NAME_DIAGNOSTIC);
  console.error(MISSING_BUTTON_NAME_DIAGNOSTIC);
}

.mrg-button {
  --mrg-button-background: var(--mrg-semantic-color-action-background);
  --mrg-button-background-hover: var(--mrg-semantic-color-action-background-hover);
  --mrg-button-background-pressed: var(--mrg-semantic-color-action-background-pressed);
  --mrg-button-border: var(--mrg-semantic-color-action-border);
  --mrg-button-foreground: var(--mrg-semantic-color-action-foreground);
  --mrg-button-min-block-size: max(
    var(--mrg-component-control-height),
    var(--mrg-semantic-size-target-minimum)
  );
  --mrg-button-padding-block: var(--mrg-component-control-padding-block);
  --mrg-button-padding-inline: var(--mrg-component-control-padding-inline);
  align-items: center;
  appearance: none;
  background: var(--mrg-button-background);
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-button-border);
  border-radius: var(--mrg-component-control-radius);
  box-sizing: border-box;
  color: var(--mrg-button-foreground);
  cursor: pointer;
  display: inline-flex;
  font-family: var(--mrg-semantic-font-family-prose);
  font-size: var(--mrg-semantic-font-size-body);
  font-weight: var(--mrg-semantic-font-weight-label);
  gap: var(--mrg-component-control-gap);
  inline-size: fit-content;
  justify-content: center;
  letter-spacing: var(--mrg-semantic-font-letter-spacing-body);
  line-height: var(--mrg-semantic-font-line-height-body);
  max-inline-size: 100%;
  min-block-size: var(--mrg-button-min-block-size);
  min-inline-size: var(--mrg-semantic-size-target-minimum);
  padding-block: var(--mrg-button-padding-block);
  padding-inline: var(--mrg-button-padding-inline);
  position: relative;
  text-align: center;
  text-decoration: none;
  transition:
    background-color var(--mrg-semantic-motion-duration-transition)
      var(--mrg-semantic-motion-easing-standard),
    border-color var(--mrg-semantic-motion-duration-transition)
      var(--mrg-semantic-motion-easing-standard),
    color var(--mrg-semantic-motion-duration-transition) var(--mrg-semantic-motion-easing-standard);
  user-select: none;
  vertical-align: middle;
}

.mrg-button[data-variant="secondary"] {
  --mrg-button-background: var(--mrg-component-control-background);
  --mrg-button-background-hover: var(--mrg-component-control-background-hover);
  --mrg-button-background-pressed: var(--mrg-component-control-background-pressed);
  --mrg-button-border: var(--mrg-component-control-border);
  --mrg-button-foreground: var(--mrg-component-control-foreground);
}

.mrg-button[data-variant="quiet"] {
  --mrg-button-background: transparent;
  --mrg-button-background-hover: var(--mrg-component-control-background-hover);
  --mrg-button-background-pressed: var(--mrg-component-control-background-pressed);
  --mrg-button-border: transparent;
  --mrg-button-foreground: var(--mrg-semantic-color-brand-action);
}

.mrg-button[data-variant="destructive"] {
  --mrg-button-background: var(--mrg-semantic-color-status-danger-background);
  --mrg-button-background-hover: color-mix(
    in oklch,
    var(--mrg-semantic-color-status-danger-background),
    var(--mrg-semantic-color-status-danger-foreground) 8%
  );
  --mrg-button-background-pressed: color-mix(
    in oklch,
    var(--mrg-semantic-color-status-danger-background),
    var(--mrg-semantic-color-status-danger-foreground) 14%
  );
  --mrg-button-border: var(--mrg-semantic-color-status-danger-border);
  --mrg-button-foreground: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-button[data-size="small"] {
  font-size: var(--mrg-semantic-font-size-label);
}

.mrg-button[data-size="medium"] {
  --mrg-button-min-block-size: max(
    var(--mrg-semantic-density-control-height),
    var(--mrg-semantic-size-target-preferred)
  );
  --mrg-button-padding-inline: var(--mrg-semantic-space-inline-lg);
}

.mrg-button[data-size="large"] {
  --mrg-button-min-block-size: calc(
    var(--mrg-semantic-size-target-preferred) + var(--mrg-semantic-space-inline-xs)
  );
  --mrg-button-padding-block: var(--mrg-semantic-space-inline-sm);
  --mrg-button-padding-inline: calc(
    var(--mrg-semantic-space-inline-lg) + var(--mrg-semantic-space-inline-xs)
  );
  font-size: var(--mrg-semantic-font-size-body-large);
}

.mrg-button:not(:disabled):not([data-pending="true"]):hover {
  background: var(--mrg-button-background-hover);
}

.mrg-button:not(:disabled):not([data-pending="true"]):active {
  background: var(--mrg-button-background-pressed);
}

.mrg-button:focus-visible {
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-button:disabled {
  --mrg-button-background: var(--mrg-component-control-background-disabled);
  --mrg-button-border: var(--mrg-component-control-border-disabled);
  --mrg-button-foreground: var(--mrg-component-control-foreground-disabled);
  cursor: not-allowed;
}

.mrg-button[data-pending="true"] {
  border-color: var(--mrg-semantic-color-status-loading-border);
  cursor: progress;
}

.mrg-button[data-pending="true"]::after {
  background: var(--mrg-semantic-color-status-loading-border);
  block-size: var(--mrg-semantic-border-width-strong);
  content: "";
  inset-block-end: 0;
  inset-inline: var(--mrg-semantic-space-inline-sm);
  position: absolute;
}

.mrg-button [data-slot="button-label"] {
  align-items: center;
  display: inline-flex;
  gap: var(--mrg-component-control-gap);
  justify-content: center;
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-button [data-slot="button-pending-indicator"] {
  animation: mrg-button-pending
    calc(
      var(--mrg-semantic-motion-duration-deliberate) +
        var(--mrg-semantic-motion-duration-transition)
    )
    linear infinite;
  aspect-ratio: 1;
  border: var(--mrg-semantic-border-width-strong) solid currentColor;
  border-block-start-color: transparent;
  border-radius: var(--mrg-semantic-radius-pill);
  flex: none;
  inline-size: var(--mrg-semantic-size-icon-sm);
}

@keyframes mrg-button-pending {
  to {
    transform: rotate(1turn);
  }
}

@media (any-pointer: coarse) {
  .mrg-button {
    min-block-size: max(
      var(--mrg-button-min-block-size),
      var(--mrg-semantic-size-target-preferred)
    );
  }
}

@media (prefers-reduced-motion: reduce) {
  .mrg-button {
    transition: none;
  }

  .mrg-button [data-slot="button-pending-indicator"] {
    animation: none;
    border-block-start-color: currentColor;
  }
}

@media (forced-colors: active) {
  .mrg-button {
    --mrg-button-background: ButtonFace;
    --mrg-button-background-hover: Highlight;
    --mrg-button-background-pressed: Highlight;
    --mrg-button-border: ButtonBorder;
    --mrg-button-foreground: ButtonText;
    forced-color-adjust: auto;
  }

  .mrg-button:not(:disabled):not([data-pending="true"]):hover,
  .mrg-button:not(:disabled):not([data-pending="true"]):active {
    color: HighlightText;
  }

  .mrg-button:focus-visible {
    box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width) Canvas;
    outline-color: Highlight;
  }

  .mrg-button:disabled {
    --mrg-button-border: GrayText;
    --mrg-button-foreground: GrayText;
  }
}

import {
  forwardRef,
  type ButtonHTMLAttributes,
  type MouseEventHandler,
  type ReactNode,
} from "react";

import {
  inspectButtonAccessibleName,
  reportButtonNameDiagnostic,
  runButtonActivation,
} from "./button-state";
import "./button.css";

export type ButtonVariant = "primary" | "secondary" | "quiet" | "destructive";
export type ButtonSize = "small" | "medium" | "large";

export interface ButtonOwnProps {
  /** Visual intent. This does not change the native button role. */
  readonly variant?: ButtonVariant;
  /** Intrinsic minimum size. Touch input raises every size to at least 44 CSS pixels. */
  readonly size?: ButtonSize;
  /** Keeps the button focusable while exposing busy/disabled semantics and blocking activation. */
  readonly pending?: boolean;
  /** Visible replacement text while pending. When omitted, the original children remain visible. */
  readonly pendingLabel?: string;
}

export interface ButtonProps
  extends ButtonOwnProps, Omit<ButtonHTMLAttributes<HTMLButtonElement>, keyof ButtonOwnProps> {
  /** Visible button label content and the default accessible-name source. */
  readonly children?: ReactNode;
}

function joinClassNames(componentClassName: string, consumerClassName: string | undefined): string {
  return consumerClassName === undefined || consumerClassName.trim().length === 0
    ? componentClassName
    : `${componentClassName} ${consumerClassName}`;
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(function Button(
  {
    "aria-busy": ariaBusy,
    "aria-disabled": ariaDisabled,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    children,
    className,
    disabled = false,
    onClick,
    pending = false,
    pendingLabel,
    size = "medium",
    type = "button",
    variant = "primary",
    ...nativeProps
  },
  ref,
) {
  reportButtonNameDiagnostic(
    inspectButtonAccessibleName({
      ariaLabel,
      ariaLabelledBy,
      children,
      title: nativeProps.title,
    }),
  );

  const handleClick: MouseEventHandler<HTMLButtonElement> | undefined =
    pending || onClick !== undefined
      ? (event) => {
          runButtonActivation(pending, event, onClick);
        }
      : undefined;
  const usablePendingLabel =
    pendingLabel !== undefined && pendingLabel.trim().length > 0 ? pendingLabel : undefined;
  const pendingLabelIsVisible = pending && usablePendingLabel !== undefined;
  const renderedAriaLabel =
    pendingLabelIsVisible && ariaLabel !== undefined ? usablePendingLabel : ariaLabel;
  const renderedAriaLabelledBy = pendingLabelIsVisible ? undefined : ariaLabelledBy;

  return (
    <button
      {...nativeProps}
      aria-busy={pending ? true : ariaBusy}
      aria-disabled={pending ? true : ariaDisabled}
      aria-label={renderedAriaLabel}
      aria-labelledby={renderedAriaLabelledBy}
      className={joinClassNames("mrg-button", className)}
      data-disabled={disabled ? "true" : undefined}
      data-pending={pending ? "true" : undefined}
      data-size={size}
      data-slot="button"
      data-variant={variant}
      disabled={disabled}
      onClick={handleClick}
      ref={ref}
      type={type}
    >
      {pending ? <span aria-hidden="true" data-slot="button-pending-indicator" /> : null}
      <span data-slot="button-label">{pendingLabelIsVisible ? usablePendingLabel : children}</span>
    </button>
  );
});

Button.displayName = "Button";
Object.defineProperty(Button, Symbol.for("mergora-ui/toolbar-action"), { value: true });
